import React, { useEffect, useMemo } from "react";
import { useSelector, useDispatch } from "react-redux";
import { Link } from "react-router-dom";
import { getAllBlogs } from "../features/ads/adsSlice";
import { getImageUrl } from "../utils/imageHelper";
import { Navigation, Pagination, Autoplay } from "swiper/modules";
import SwiperCore from "swiper";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css/bundle";
import "./popads.css";
SwiperCore.use([Navigation, Pagination, Autoplay]);

function HomeAds({ category: propCategory }) {
  const dispatch = useDispatch();
  const { blog: adData, realAds, isLoading } = useSelector((state) => state.blog);

  const displayAds = useMemo(() => {
    let combined = [];
    
    // Add new dedicated AdHome table entries
    if (realAds?.homeAds?.length > 0) {
      combined = [...combined, ...realAds.homeAds];
    }
    
    // Add Legacy Blog-based Main Slider ads
    if (adData?.length > 0) {
      const legacy = adData.filter((item) => item.category === "Main Slider");
      combined = [...combined, ...legacy];
    }

    // Sort by creation date and limit to top 5
    return combined.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt)).slice(0, 5);
  }, [adData, realAds]);

  if (isLoading) {
    return (
      <div className="flex space-x-2 justify-center items-center h-[200px] md:h-[400px] bg-teal-50/10 mt-2 rounded-2xl">
        <span className="sr-only">Loading Ads...</span>
        <div className="h-2 w-2 bg-teal-600 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
        <div className="h-2 w-2 bg-teal-600 rounded-full animate-bounce [animation-delay:-1.15s]"></div>
        <div className="h-2 w-2 bg-teal-600 rounded-full animate-bounce"></div>
      </div>
    );
  }

  if (displayAds.length === 0) {
    return null;
  }

  return (
    <div className="w-full mb-0 overflow-hidden md:px-4 lg:px-6">
      <div className="overflow-hidden shadow-2xl relative">
        <style>{`
          .home-ads-swiper .swiper-pagination-bullet {
              background: #94a3b8 !important;
              opacity: 0.3 !important;
              width: 8px !important;
              height: 8px !important;
              margin: 0 4px !important;
              transition: all 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275) !important;
          }
          .home-ads-swiper .swiper-pagination-bullet-active { 
              background: #14b8a6 !important;
              width: 24px !important;
              opacity: 1 !important;
              border-radius: 4px !important;
              box-shadow: 0 0 10px rgba(20, 184, 166, 0.3) !important;
          }
          .home-ads-swiper .swiper-pagination {
              bottom: 20px !important;
          }
      `}</style>
        <div className="hero-slider-container">
          <Swiper
            spaceBetween={0}
            slidesPerView={1}
            navigation={false}
            pagination={{ clickable: true }}
            autoplay={{ delay: 6000, disableOnInteraction: false }}
            loop={displayAds.length > 1}
            className="h-[260px] md:h-[380px] lg:h-[460px] home-ads-swiper"
          >
            {displayAds?.map((ad, index) => {
              const imgSrc = ad.image || (ad.images?.secure_url || ad.images?.[0]?.secure_url) || "";
              return (
                <SwiperSlide key={ad._id || index}>
                  <div className="w-full h-full relative overflow-hidden group">
                    <img
                      src={imgSrc}
                      alt={ad.title}
                      className="w-full h-full object-cover"
                    />
                    {/* Modern Professional Overlay */}
                    <div className="absolute inset-0 bg-gradient-to-r from-teal-900/80 via-teal-900/40 to-transparent"></div>

                    <div className="absolute inset-0 flex flex-col justify-center px-10 md:px-24 lg:px-40">
                      <div className="max-w-3xl animate-fadeIn">
                        {/* Removed Official Pharmacy Premium text per request */}
                        <h2 className="text-xl md:text-5xl lg:text-7xl font-black text-white leading-tight mb-3 drop-shadow-2xl uppercase tracking-tighter">
                          {ad.title}
                        </h2>
                        <div
                          className="text-white/90 text-[11px] md:text-lg font-medium mb-4 line-clamp-1 md:line-clamp-3 max-w-2xl leading-relaxed hidden md:block"
                          dangerouslySetInnerHTML={{ __html: ad.description }}
                        ></div>
                        <div className="flex flex-wrap gap-3">
                          <Link
                            to={ad.path || "/shop"}
                            className="px-5 py-2.5 bg-teal-400 text-teal-950 font-black uppercase tracking-widest text-[10px] md:text-xs rounded-lg hover:bg-white hover:text-teal-600 transition-all shadow-xl active:scale-95 text-center"
                          >
                            Explore Now
                          </Link>
                          <Link
                            to="/category"
                            className="px-5 py-2.5 bg-white/10 backdrop-blur-md border border-white/30 text-white font-black uppercase tracking-widest text-[10px] md:text-xs rounded-lg hover:bg-white/20 transition-all text-center hidden md:inline-flex"
                          >
                            Browse All
                          </Link>
                        </div>
                      </div>
                    </div>
                  </div>
                </SwiperSlide>
              );
            })}
          </Swiper>
        </div>
      </div>
    </div>
  );
}

export default HomeAds;
